import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const Profile = () => {
  const navigate = useNavigate();
  const userId = localStorage.getItem("userId");

  const [image, setImage] = useState("");
  const [name, setName] = useState("");
  const [bio, setBio] = useState("");

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
    setImage(data.image || "");
    setName(data.name || "");
    setBio(data.bio || "");
  }, [userId]);

  const handleImage = (e) => {
    const file = e.target.files[0];
    const reader = new FileReader();

    reader.onloadend = () => {
      setImage(reader.result);
    };

    if (file) reader.readAsDataURL(file);
  };

  const handleSave = () => {
    const data = { image, name, bio };
    localStorage.setItem(`profile_${userId}`, JSON.stringify(data));
    alert("Profile Saved ✅");
  };

  return (
    <div style={container}>

      {/* 🔙 Back Button */}
      <button onClick={() => navigate("/dashboard")} style={backBtn}>
        ⬅ Back
      </button>

      <h2>My Profile</h2>

      {/* Image */}
      <img
        src={image || "https://via.placeholder.com/150"}
         alt="User Profile"
  style={imgStyle}
      />

      <input type="file" onChange={handleImage} />

      {/* Name */}
      <input
        type="text"
        placeholder="Enter Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        style={input}
      />

      {/* Bio */}
      <textarea
        placeholder="Write your bio..."
        value={bio}
        onChange={(e) => setBio(e.target.value)}
        style={textarea}
      />

      <button onClick={handleSave} style={btn}>
        Save Profile
      </button>
    </div>
  );
};

const container = {
  height: "100vh",
  width: "100%",
  background: "#f4f4f4",
  textAlign: "center",
  paddingTop: "80px",
};

const backBtn = {
  position: "absolute",
  left: "20px",
  top: "20px",
  padding: "10px",
  background: "#333",
  color: "#fff",
  border: "none",
  cursor: "pointer",
};

const imgStyle = {
  width: "130px",
  height: "130px",
  borderRadius: "50%",
  marginBottom: "15px",
};

const input = {
  display: "block",
  margin: "10px auto",
  padding: "10px",
  width: "250px",
};

const textarea = {
  display: "block",
  margin: "10px auto",
  padding: "10px",
  width: "250px",
  height: "80px",
};

const btn = {
  padding: "10px 20px",
  background: "#ff6b6b",
  color: "#fff",
  border: "none",
  cursor: "pointer",
};

export default Profile;
